#!/usr/bin/env bash
# code/cluster/vendor/jsonl-write.sh — Append-only JSONL run-log writer.
#
# Vendored from dr-fleet-evolution/lib/jsonl.sh (Datarim framework).
# Provenance: /Users/ug/arcanada/Projects/Datarim/code/datarim/plugins/
#             dr-fleet-evolution/lib/jsonl.sh
# Vendored at: 2026-06-21.
# Purpose: provide the append-only audit trail for cubrim-run-log.jsonl (Law 5).
# Do NOT edit this file — update from source and re-vendor if needed.
#
# Differences from upstream: the emit function signature is extended to
# support run-log fields (run_id, event, gate, verdict, detail) in addition
# to the fleet-evolution contract fields. The upstream validation checks
# the fleet contract; this file adds cubrim-specific emitters.

set -o pipefail

# ── Upstream functions (verbatim from dr-fleet-evolution/lib/jsonl.sh) ────────

jsonl_require_jq() {
    if ! command -v jq >/dev/null 2>&1; then
        echo "jsonl: jq not found on PATH (required for JSONL validation)" >&2
        return 3
    fi
}

# Emit a fleet-evolution schema JSONL record (upstream contract).
jsonl_emit_record() {
    local task_input=$1 expected_output=$2 actual_output=$3 outcome=$4 source=$5
    jq -cn \
        --arg ti "$task_input" \
        --arg eo "$expected_output" \
        --arg ao "$actual_output" \
        --arg oc "$outcome" \
        --arg src "$source" \
        '{task_input:$ti, expected_output:$eo, actual_output:$ao, outcome:$oc, source:$src}'
}

# ── Cubrim run-log extension ──────────────────────────────────────────────────

# Emit a cubrim run-log record (Law 5 audit trail).
# Required for every gate result, merge, and leaderboard write.
#
# Usage: cubrim_log_event <run_log> <run_id> <event> [key=value ...]
#
# key=value pairs are emitted as JSON fields. String values only.
# Appends a single line to <run_log>.
#
# Example:
#   cubrim_log_event datarim/cubrim-run-log.jsonl iter-001 gate_pass \
#       gate=gate-corpus-hash verdict=PASS detail=""
cubrim_log_event() {
    local run_log="$1" run_id="$2" event="$3"
    shift 3

    jsonl_require_jq || return 3

    local ts
    ts="$(date -u '+%Y-%m-%dT%H:%M:%SZ')"

    # Build the jq args dynamically from key=value pairs
    local jq_args=()
    local jq_fields='{ts:$ts, run_id:$run_id, event:$event'
    jq_args+=(--arg ts "$ts" --arg run_id "$run_id" --arg event "$event")

    local kv key val
    for kv in "$@"; do
        key="${kv%%=*}"
        val="${kv#*=}"
        jq_args+=(--arg "$key" "$val")
        jq_fields+=", ${key}:\$${key}"
    done
    jq_fields+='}'

    jq -cn "${jq_args[@]}" "$jq_fields" >> "$run_log"
}

# Assert that a leaderboard write has a run_log_ref (Law 5 traceability invariant).
# Usage: cubrim_assert_run_log_ref <leaderboard_json> <run_id>
# Exits non-zero if the run_id entry lacks run_log_ref.
cubrim_assert_run_log_ref() {
    local leaderboard="$1" run_id="$2"
    jsonl_require_jq || return 3

    local ref
    ref="$(jq -r --arg rid "$run_id" '
        .runs[]
        | select(.run_id == $rid)
        | .run_log_ref // ""
    ' "$leaderboard" 2>/dev/null || echo "")"

    if [ -z "$ref" ]; then
        echo "cubrim_assert_run_log_ref: FAIL — run_id '$run_id' missing run_log_ref in $leaderboard" >&2
        return 1
    fi
    echo "cubrim_assert_run_log_ref: OK — run_id '$run_id' → run_log_ref '$ref'"
    return 0
}
